import React, { useCallback, useRef } from 'react';
import { useDiagramState } from './hooks/useDiagramState';
import { getBounds } from './utils/geometry';
import { toPng, toSvg } from 'html-to-image';
import Toolbar from './components/Toolbar/Toolbar';
import Sidebar from './components/Sidebar/Sidebar';
import Canvas from './components/Canvas/Canvas';
import MiniMap from './components/Canvas/MiniMap';
import SqlModal from './components/Modals/SqlModal';
import ImportModal from './components/Modals/ImportModal';

export default function App() {
  const canvasRef = useRef(null);
  const ds = useDiagramState();
  const { 
    nodes, setNodes, edges, setEdges, selectedItem, setSelectedItem,
    pan, setPan, zoom, setZoom, mode, setMode, snapToGrid, setSnapToGrid,
    isDragging, setIsDragging, dragOffset, setDragOffset,
    mousePos, setMousePos, dragConnectStart, setDragConnectStart,
    sqlModalOpen, setSqlModalOpen, importModalOpen, setImportModalOpen,
    exportSettings, setExportSettings,
    commitAction, undo, redo, updateSelectedNode, updateEdgeProperties,
    deleteSelectedItem, handleDuplicate, alignNeighbors, createAggregation,
    clearCanvas, darkMode, setDarkMode
  } = ds;

  // --- INTERACTION HANDLERS (Re-implemented in App for context) ---
  const getPos = (e) => ({ clientX: e.clientX ?? e.touches?.[0]?.clientX ?? 0, clientY: e.clientY ?? e.touches?.[0]?.clientY ?? 0 });

  const handlePointerDown = (e, type, item) => {
    e.stopPropagation();
    if (mode === 'select') {
      setSelectedItem({ type, id: item.id });
      if (type === 'node') {
        setIsDragging(true);
        const { clientX, clientY } = getPos(e);
        let rawX = (clientX - pan.x) / zoom; let rawY = (clientY - pan.y) / zoom;
        const bounds = getBounds(item, nodes, edges);
        setDragOffset({ x: rawX - bounds.x, y: rawY - bounds.y });
      }
    }
  };

  const handlePointerMove = (e) => {
    const { clientX, clientY } = getPos(e);
    let rawX = (clientX - pan.x) / zoom; let rawY = (clientY - pan.y) / zoom;
    if (isNaN(rawX) || isNaN(rawY)) return;
    setMousePos({ x: rawX, y: rawY });

    if (isDragging && selectedItem?.type === 'node' && !dragConnectStart) {
      const activeNode = nodes.find(n => n.id === selectedItem.id);
      if(activeNode && activeNode.shape === 'aggregation') return; 

      if (snapToGrid) { rawX = Math.round(rawX / 24) * 24; rawY = Math.round(rawY / 24) * 24; }
      setNodes(nodes.map(n => n.id === selectedItem.id ? { ...n, x: rawX - dragOffset.x, y: rawY - dragOffset.y } : n));
    } else if (isDragging && mode === 'select' && !selectedItem && !dragConnectStart) {
      setPan({ x: pan.x + e.movementX, y: pan.y + e.movementY });
    }
  };

  const handlePointerUp = () => {
    if (isDragging && !dragConnectStart) commitAction(nodes, edges);
    setIsDragging(false); setDragConnectStart(null);
  };

  const handleNodePointerUp = (e, targetNode) => {
    e.stopPropagation();
    if (dragConnectStart && dragConnectStart.id !== targetNode.id) {
      const src = dragConnectStart; const tgt = targetNode;
      let newNodes = [...nodes]; let newEdges = [...edges];

      if (src.shape === 'rectangle' && tgt.shape === 'rectangle') {
        const midX = (src.x + tgt.x) / 2; const midY = (src.y + tgt.y) / 2;
        const newDiamondId = `node_${Date.now()}`;
        newNodes.push({ id: newDiamondId, shape: 'diamond', name: `rel_${src.name}`, x: midX, y: midY, isWeak: false });
        newEdges.push(
          { id: `edge_${Date.now()}_1`, source: newDiamondId, target: src.id, cardinality: '1', participation: 'partial' },
          { id: `edge_${Date.now()}_2`, source: newDiamondId, target: tgt.id, cardinality: 'N', participation: 'partial' }
        );
      } else {
        newEdges.push({ id: `edge_${Date.now()}`, source: src.id, target: tgt.id, cardinality: 'N', participation: 'partial' });
      }
      commitAction(newNodes, newEdges);
    }
    setIsDragging(false); setDragConnectStart(null);
  };

  const handleCanvasPointerDown = (e) => {
    const { clientX, clientY } = getPos(e);
    let rawX = (clientX - pan.x) / zoom; let rawY = (clientY - pan.y) / zoom;
    if (isNaN(rawX) || isNaN(rawY)) return;
    if (snapToGrid) { rawX = Math.round(rawX / 24) * 24; rawY = Math.round(rawY / 24) * 24; }

    if (['add-rect', 'add-dia', 'add-attr', 'add-isa'].includes(mode)) {
      const shapeMap = { 'add-rect': 'rectangle', 'add-dia': 'diamond', 'add-attr': 'attribute', 'add-isa': 'isa' };
      const newNode = {
        id: `node_${Date.now()}`, shape: shapeMap[mode], name: shapeMap[mode] === 'isa' ? 'ISA' : `new_${shapeMap[mode]}`, 
        x: rawX - 60, y: rawY - 30, isWeak: false, color: 'bg-[#bae6fd]',
        attributes: shapeMap[mode] === 'rectangle' ? [{ id: `a_${Date.now()}`, name: 'id', type: 'INT', isPK: true, isFK: false, isNullable: false, indent: 0 }] : undefined,
        constraint: shapeMap[mode] === 'isa' ? 'disjoint' : undefined, completeness: shapeMap[mode] === 'isa' ? 'partial' : undefined
      };
      commitAction([...nodes, newNode], edges);
      setMode('select'); setSelectedItem({ type: 'node', id: newNode.id });
    } else if (mode === 'select') {
      setSelectedItem(null); setIsDragging(true);
    }
  };

  const handleSave = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ nodes, edges }));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "er_workspace.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleLoad = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = JSON.parse(e.target.result);
        if (data.nodes && data.edges) {
          setNodes(data.nodes);
          setEdges(data.edges);
          setSelectedItem(null);
        }
      } catch (err) { alert("Invalid workspace file"); }
    };
    reader.readAsText(file);
    e.target.value = null;
  };

  const exportImage = async (format) => {
    if (!canvasRef.current) return;
    try {
      const filter = (node) => !node.classList?.contains('port-handle'); // Exclude ports
      const options = { filter, backgroundColor: ds.darkMode ? '#0a0a0a' : '#f8fafc' };

      let dataUrl;
      if (format === 'png') dataUrl = await toPng(canvasRef.current, options);
      else dataUrl = await toSvg(canvasRef.current, options);

      const link = document.createElement('a');
      link.download = `er_diagram.${format}`;
      link.href = dataUrl;
      link.click();
    } catch (err) { console.error('Export failed', err); }
  };

  return (
    <div className={`flex h-screen w-full ${darkMode ? 'bg-neutral-950 text-neutral-200' : 'bg-[#f1f5f9] text-neutral-800'} overflow-hidden font-serif selection:bg-sky-200 relative`}>
      <Toolbar 
        mode={mode} setMode={setMode} 
        undo={undo} redo={redo} pastCount={ds.past.length} futureCount={ds.future.length}
        snapToGrid={snapToGrid} setSnapToGrid={setSnapToGrid}
        setZoom={setZoom} handleSave={handleSave} handleLoad={handleLoad}
        setSqlModalOpen={setSqlModalOpen}
        setImportModalOpen={setImportModalOpen}
        darkMode={darkMode} setDarkMode={setDarkMode}
        handleExport={exportImage}
      />

      <Canvas 
        canvasRef={canvasRef}
        nodes={nodes} edges={edges} selectedItem={selectedItem}
        pan={pan} zoom={zoom} mode={mode} snapToGrid={snapToGrid}
        isDragging={isDragging} mousePos={mousePos} dragConnectStart={dragConnectStart}
        handleCanvasPointerDown={handleCanvasPointerDown}
        handlePointerMove={handlePointerMove}
        handlePointerUp={handlePointerUp}
        handlePointerDown={handlePointerDown}
        handleNodePointerUp={handleNodePointerUp}
        setDragConnectStart={setDragConnectStart}
        darkMode={darkMode}
      />

      <MiniMap nodes={nodes} edges={edges} pan={pan} zoom={zoom} darkMode={darkMode} />

      <Sidebar 
        selectedItem={selectedItem} setSelectedItem={setSelectedItem}
        nodes={nodes} edges={edges}
        updateSelectedNode={updateSelectedNode}
        updateEdgeProperties={updateEdgeProperties}
        deleteSelectedItem={deleteSelectedItem}
        handleDuplicate={handleDuplicate}
        alignNeighbors={alignNeighbors}
        createAggregation={createAggregation}
        commitAction={commitAction}
        clearCanvas={clearCanvas}
        darkMode={darkMode}
      />

      <SqlModal 
        nodes={nodes} edges={edges}
        sqlModalOpen={sqlModalOpen} setSqlModalOpen={setSqlModalOpen}
        exportSettings={exportSettings} setExportSettings={setExportSettings}
        darkMode={darkMode}
      />

      <ImportModal 
        isOpen={importModalOpen} 
        onClose={() => setImportModalOpen(false)} 
        onImport={(n, e) => commitAction(n, e)}
        darkMode={darkMode}
      />
      <style dangerouslySetInnerHTML={{__html: `
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
      `}} />
    </div>
  );
}

import React from 'react';
import { Key, Link as LinkIcon, Triangle } from 'lucide-react';
import { getBounds, getEdgeIntersection } from '../../utils/geometry';

export function Port({ position, setDragConnectStart, node }) {
  const classes = {
    top: 'top-0 left-1/2 -translate-x-1/2 -translate-y-1/2',
    right: 'top-1/2 right-0 translate-x-1/2 -translate-y-1/2',
    bottom: 'bottom-0 left-1/2 -translate-x-1/2 translate-y-1/2',
    left: 'top-1/2 left-0 -translate-x-1/2 -translate-y-1/2'
  };
  return (
    <div onPointerDown={(e) => { e.stopPropagation(); setDragConnectStart(node); }}
      className={`port-handle absolute w-3.5 h-3.5 bg-sky-500 border-2 border-white rounded-full opacity-0 group-hover:opacity-100 hover:scale-150 transition-all duration-200 cursor-crosshair shadow-md z-30 ${classes[position]}`}
    />
  );
}

export default function Canvas({ 
  canvasRef,
  nodes, edges, selectedItem, pan, zoom, mode, snapToGrid,
  isDragging, mousePos, dragConnectStart, 
  handleCanvasPointerDown, handlePointerMove, handlePointerUp, handlePointerDown, handleNodePointerUp, setDragConnectStart,
  darkMode
}) {
  return (
    <div 
      ref={canvasRef}
      className="flex-1 relative overflow-hidden cursor-grab active:cursor-grabbing"
      style={{ 
        backgroundImage: darkMode ? 'radial-gradient(#334155 1.5px, transparent 1.5px)' : 'radial-gradient(#cbd5e1 1.5px, transparent 1.5px)', 
        backgroundSize: `${24 * zoom}px ${24 * zoom}px`, 
        backgroundPosition: `${pan.x}px ${pan.y}px` 
      }}
      onPointerDown={handleCanvasPointerDown} 
      onPointerMove={handlePointerMove} 
      onPointerUp={handlePointerUp} 
      onPointerLeave={handlePointerUp}
    >
      <div className="absolute top-0 left-0 w-full h-full origin-top-left" style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${zoom})` }}>
        
        {/* SVG Markers */}
        <svg className="absolute w-0 h-0">
          <defs>
            <marker id="arrow-end" markerWidth="14" markerHeight="14" refX="10" refY="5" orient="auto"><polygon points="0,0 10,5 0,10" fill={darkMode ? "#94a3b8" : "#334155"} /></marker>
            <marker id="arrow-start" markerWidth="14" markerHeight="14" refX="0" refY="5" orient="auto-start-reverse"><polygon points="0,0 10,5 0,10" fill={darkMode ? "#94a3b8" : "#334155"} /></marker>
            <marker id="arrow-end-selected" markerWidth="14" markerHeight="14" refX="10" refY="5" orient="auto"><polygon points="0,0 10,5 0,10" fill="#0284c7" /></marker>
            <marker id="arrow-start-selected" markerWidth="14" markerHeight="14" refX="0" refY="5" orient="auto-start-reverse"><polygon points="0,0 10,5 0,10" fill="#0284c7" /></marker>
          </defs>
        </svg>

        {/* SVG EDGES OVERLAY */}
        <svg className="absolute inset-0 w-full h-full pointer-events-none" style={{ overflow: 'visible' }}>
          {edges.map(edge => {
            const srcNode = nodes.find(n => n.id === edge.source);
            const tgtNode = nodes.find(n => n.id === edge.target);
            if (!srcNode || !tgtNode) return null;

            const p1 = getEdgeIntersection(srcNode, getBounds(tgtNode, nodes, edges), nodes, edges);
            const p2 = getEdgeIntersection(tgtNode, getBounds(srcNode, nodes, edges), nodes, edges);
            
            if (!p1 || !p2 || isNaN(p1.x) || isNaN(p1.y) || isNaN(p2.x) || isNaN(p2.y)) return null;
            
            const isSelected = selectedItem?.type === 'edge' && selectedItem?.id === edge.id;
            const strokeColor = isSelected ? "#0284c7" : (darkMode ? "#64748b" : "#334155");
            
            let drawTargetArrow = (edge.cardinality === '1' && srcNode.shape === 'diamond') || (srcNode.shape === 'isa' && srcNode.parentId === tgtNode.id);
            let drawSourceArrow = (edge.cardinality === '1' && tgtNode.shape === 'diamond') || (tgtNode.shape === 'isa' && tgtNode.parentId === srcNode.id);

            const markerEnd = drawTargetArrow ? (isSelected ? 'url(#arrow-end-selected)' : 'url(#arrow-end)') : 'none';
            const markerStart = drawSourceArrow ? (isSelected ? 'url(#arrow-start-selected)' : 'url(#arrow-start)') : 'none';

            const dx = p2.x - p1.x; const dy = p2.y - p1.y; const len = Math.hypot(dx, dy);
            const nx = len > 0 ? (-dy / len) * 2.5 : 0; const ny = len > 0 ? (dx / len) * 2.5 : 0;
            
            const midX = (p1.x + p2.x) / 2; const midY = (p1.y + p2.y) / 2;

            return (
              <g key={edge.id} className="pointer-events-auto cursor-pointer" onPointerDown={(e) => handlePointerDown(e, 'edge', edge)}>
                <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke="transparent" strokeWidth={16} />
                {edge.participation === 'total' ? (
                  <>
                    <line x1={p1.x + nx} y1={p1.y + ny} x2={p2.x + nx} y2={p2.y + ny} stroke={strokeColor} strokeWidth={1.5} markerStart={markerStart} markerEnd={markerEnd} />
                    <line x1={p1.x - nx} y1={p1.y - ny} x2={p2.x - nx} y2={p2.y - ny} stroke={strokeColor} strokeWidth={1.5} />
                  </>
                ) : (
                  <line x1={p1.x} y1={p1.y} x2={p2.x} y2={p2.y} stroke={strokeColor} strokeWidth={1.5} strokeDasharray={edge.dashed ? "6,4" : "none"} markerStart={markerStart} markerEnd={markerEnd} />
                )}
                {edge.label && (
                  <g transform={`translate(${midX}, ${midY})`}>
                    <rect x="-24" y="-10" width="48" height="20" fill={darkMode ? "#171717" : "white"} rx="4" opacity="0.9" />
                    <text textAnchor="middle" dominantBaseline="middle" dy="1" fontSize="10" fontWeight="bold" fill={darkMode ? "#38bdf8" : "#0369a1"} className="font-sans select-none">{edge.label}</text>
                  </g>
                )}
              </g>
            );
          })}
          {dragConnectStart && !isNaN(mousePos.x) && !isNaN(mousePos.y) && (
            <line 
              x1={getBounds(dragConnectStart, nodes, edges).cx} 
              y1={getBounds(dragConnectStart, nodes, edges).cy} 
              x2={mousePos.x} 
              y2={mousePos.y} 
              stroke="#0ea5e9" strokeWidth={2} strokeDasharray="5,5" 
            />
          )}
        </svg>

        {/* HTML NODES OVERLAY */}
        {nodes.map(node => {
          const bounds = getBounds(node, nodes, edges);
          const isSelected = selectedItem?.type === 'node' && selectedItem?.id === node.id;
          const isCurrentlyDragging = isSelected && isDragging && !dragConnectStart;
          
          if (node.shape === 'aggregation') {
             return (
                <div key={node.id} onPointerDown={(e) => handlePointerDown(e, 'node', node)} onPointerUp={(e) => handleNodePointerUp(e, node)}
                     className={`absolute border-2 border-dashed border-sky-400 bg-sky-50/30 rounded-xl transition-all ${isSelected ? 'ring-2 ring-sky-500 shadow-lg' : ''}`}
                     style={{ left: bounds.x, top: bounds.y, width: bounds.w, height: bounds.h, zIndex: 0 }}>
                     <div className="absolute -top-6 left-2 text-xs font-bold text-sky-600 bg-sky-50 px-2 py-0.5 rounded-md border border-sky-200">{node.name}</div>
                     {!isCurrentlyDragging && <><Port node={node} position="top" setDragConnectStart={setDragConnectStart} /><Port node={node} position="right" setDragConnectStart={setDragConnectStart} /><Port node={node} position="bottom" setDragConnectStart={setDragConnectStart} /><Port node={node} position="left" setDragConnectStart={setDragConnectStart} /></>}
                </div>
             );
          }

          let shapeClasses = `absolute flex items-center justify-center select-none group 
            ${isCurrentlyDragging ? 'scale-105 shadow-2xl opacity-90 z-50' : 'transition-all duration-200 ease-out hover:-translate-y-1 hover:shadow-xl shadow-md z-10'} 
            ${isSelected && !isCurrentlyDragging ? 'ring-2 ring-sky-500 shadow-xl z-20' : ''}`;

          const renderedAttrs = node.attributes?.map((attr, i, arr) => ({
            ...attr, isCompositeParent: arr[i+1] && (arr[i+1].indent || 0) > (attr.indent || 0)
          }));

          return (
            <div key={node.id} onPointerDown={(e) => handlePointerDown(e, 'node', node)} onPointerUp={(e) => handleNodePointerUp(e, node)} className={shapeClasses} style={{ left: bounds.x, top: bounds.y, width: bounds.w, height: bounds.h, borderRadius: node.shape === 'rectangle' ? '12px' : '0' }}>
              {!isCurrentlyDragging && <><Port node={node} position="top" setDragConnectStart={setDragConnectStart} /><Port node={node} position="right" setDragConnectStart={setDragConnectStart} /><Port node={node} position="bottom" setDragConnectStart={setDragConnectStart} /><Port node={node} position="left" setDragConnectStart={setDragConnectStart} /></>}

              {node.shape === 'rectangle' && (
                <div className={`w-full h-full ${darkMode ? 'bg-neutral-900/95 border-neutral-700' : 'bg-white/95 border-neutral-800'} backdrop-blur-sm border flex flex-col rounded-xl overflow-hidden ${node.isWeak ? 'border-[3px] border-double' : ''}`}>
                  <div className={`${node.color || (darkMode ? 'bg-sky-900/50' : 'bg-[#bae6fd]')} ${darkMode ? 'border-neutral-700 text-neutral-100' : 'border-neutral-800 text-neutral-900'} border-b h-[32px] flex items-center justify-center font-bold text-[15px] italic tracking-wide transition-colors`}>
                    {node.name}
                  </div>
                  <div className="flex-1 py-1 px-3 flex flex-col gap-1">
                    {renderedAttrs?.map(attr => {
                      let displayName = attr.name;
                      if (attr.isMultivalued) displayName = `{${displayName}}`;
                      if (attr.isDerived) displayName = `${displayName}()`;
                      return (
                        <div key={attr.id} className={`${darkMode ? 'text-neutral-300' : 'text-neutral-800'} text-[12px] flex items-center justify-between h-[24px]`} style={{ paddingLeft: `${(attr.indent || 0) * 12}px` }}>
                          <div className="flex items-center gap-1 truncate pr-2">
                            {attr.isPK && <Key size={10} className="text-amber-500 shrink-0" />}
                            {attr.isFK && !attr.isPK && <LinkIcon size={10} className="text-emerald-500 shrink-0" />}
                            <span className={`truncate ${attr.isPK ? 'underline underline-offset-2 font-bold' : attr.isPartialKey ? `border-b border-dashed ${darkMode ? 'border-neutral-500' : 'border-neutral-800'} font-bold` : 'font-medium'} ${attr.isDerived ? 'italic text-neutral-500' : ''}`}>
                              {displayName}
                            </span>
                          </div>
                          {!attr.isCompositeParent && <span className="text-[10px] text-neutral-500 font-sans font-mono shrink-0">{attr.type}</span>}
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}

              {node.shape === 'diamond' && (
                <div className="relative w-full h-full flex items-center justify-center">
                  <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible" viewBox="0 0 140 70" preserveAspectRatio="none">
                    {node.isWeak ? (
                      <><polygon points="70,0 140,35 70,70 0,35" fill={darkMode ? "#0c4a6e" : "#e0f2fe"} stroke={darkMode ? "#94a3b8" : "#262626"} strokeWidth="2" strokeLinejoin="round" /><polygon points="70,6 130,35 70,64 10,35" fill="none" stroke={darkMode ? "#94a3b8" : "#262626"} strokeWidth="1.2" strokeLinejoin="round" /></>
                    ) : ( <polygon points="70,0 140,35 70,70 0,35" fill={darkMode ? "#0f172a" : "#f0f9ff"} stroke={darkMode ? "#64748b" : "#262626"} strokeWidth="1.5" strokeLinejoin="round" /> )}
                  </svg>
                  <span className={`relative z-10 font-bold italic text-[14px] ${darkMode ? 'text-neutral-100' : 'text-neutral-900'} px-4 text-center`}>{node.name}</span>
                </div>
              )}

              {node.shape === 'isa' && (
                <div className="relative w-full h-full flex flex-col items-center justify-center pt-2">
                  <svg className="absolute inset-0 w-full h-full pointer-events-none overflow-visible" viewBox="0 0 80 70" preserveAspectRatio="none">
                     <polygon points="40,0 80,70 0,70" fill={darkMode ? "#1e293b" : "#ffffff"} stroke={darkMode ? "#64748b" : "#262626"} strokeWidth="1.5" strokeLinejoin="round" />
                  </svg>
                  <span className={`relative z-10 font-bold text-[14px] ${darkMode ? 'text-neutral-100' : 'text-neutral-900'} px-2 mt-2 text-center tracking-widest`}>{node.name}</span>
                  <span className="relative z-10 text-[10px] font-bold text-sky-700 bg-sky-50 rounded-full w-4 h-4 flex items-center justify-center -mt-1 shadow-sm border border-sky-200">{node.constraint === 'overlapping' ? 'o' : 'd'}</span>
                </div>
              )}

              {node.shape === 'attribute' && (
                <div className={`w-full h-full ${darkMode ? 'bg-neutral-900/95 border-neutral-700 text-neutral-300' : 'bg-white/95 border-neutral-800 text-neutral-800'} backdrop-blur-sm border flex items-center justify-center text-[13px] font-medium rounded-full`}>
                  {node.name}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { Sparkles, X, FileJson, AlertCircle } from 'lucide-react';

export default function ImportModal({ 
  isOpen, onClose, onImport, darkMode 
}) {
  const [input, setInput] = useState('');
  const [error, setError] = useState(null);

  if (!isOpen) return null;

  const handleProcess = () => {
    try {
      const data = JSON.parse(input);
      // Basic heuristic: if it's an array of objects, treat as entities
      // If it's an object with keys, treat keys as entities
      let entities = [];
      if (Array.isArray(data)) {
        entities = data;
      } else if (typeof data === 'object') {
        entities = Object.entries(data).map(([name, props]) => ({ name, ...props }));
      }

      const nodes = entities.map((ent, i) => ({
        id: `node_gen_${Date.now()}_${i}`,
        name: ent.name || `entity_${i}`,
        shape: 'rectangle',
        x: 100 + (i % 3) * 250,
        y: 100 + Math.floor(i / 3) * 200,
        color: 'bg-[#bae6fd]',
        attributes: Object.entries(ent).filter(([k]) => k !== 'name' && typeof ent[k] !== 'object').map(([k, v], j) => ({
          id: `attr_${Date.now()}_${i}_${j}`,
          name: k,
          type: typeof v === 'number' ? 'INT' : 'VARCHAR(255)',
          isPK: k.toLowerCase() === 'id' || k.toLowerCase().endsWith('_id'),
          indent: 0
        }))
      }));

      onImport(nodes, []);
      onClose();
    } catch (err) {
      setError("Invalid JSON format. Please check your input.");
    }
  };

  return (
    <div className="fixed inset-0 bg-neutral-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4 font-sans animate-in fade-in duration-200">
      <div className={`border ${darkMode ? 'bg-neutral-900 border-neutral-700 shadow-[0_0_50px_rgba(0,0,0,0.5)]' : 'bg-white border-neutral-200 shadow-2xl'} rounded-2xl w-full max-w-2xl flex flex-col overflow-hidden transform transition-all`}>
        <div className={`flex items-center justify-between px-6 py-4 border-b ${darkMode ? 'border-neutral-800 bg-neutral-900 text-neutral-100' : 'border-neutral-100 bg-white text-neutral-800'}`}>
          <div className="flex items-center gap-2 font-bold text-lg"><Sparkles size={22} className="text-amber-500" /> AI-Assisted Import</div>
          <button onClick={onClose} className="text-neutral-400 hover:text-neutral-800 p-1 hover:bg-neutral-100 dark:hover:bg-neutral-800 rounded-full transition-colors"><X size={20} /></button>
        </div>
        
        <div className="p-6 space-y-4">
          <p className={`text-sm ${darkMode ? 'text-neutral-400' : 'text-neutral-500'}`}>
            Paste a JSON structure or a list of entities to automatically generate a diagram.
          </p>
          
          <textarea 
            value={input}
            onChange={(e) => { setInput(e.target.value); setError(null); }}
            placeholder='[{"name": "User", "id": 1, "username": "string"}, {"name": "Post", "id": 1, "title": "string"}]'
            className={`w-full h-64 font-mono text-sm p-4 rounded-xl border focus:outline-none focus:ring-2 focus:ring-sky-500/20 transition-all ${darkMode ? 'bg-neutral-800 border-neutral-700 text-neutral-200' : 'bg-neutral-50 border-neutral-200 text-neutral-700'}`}
          />
          
          {error && (
            <div className="flex items-center gap-2 text-red-500 bg-red-500/10 p-3 rounded-lg text-sm border border-red-500/20">
              <AlertCircle size={16} /> {error}
            </div>
          )}
        </div>

        <div className={`p-4 border-t ${darkMode ? 'border-neutral-800 bg-neutral-900' : 'border-neutral-100 bg-neutral-50'} flex justify-end gap-3`}>
          <button onClick={onClose} className={`px-5 py-2.5 rounded-xl text-sm font-semibold ${darkMode ? 'text-neutral-400 hover:bg-neutral-800' : 'text-neutral-600 hover:bg-neutral-200'} transition-colors`}>Cancel</button>
          <button onClick={handleProcess} className="px-5 py-2.5 rounded-xl text-sm font-semibold bg-amber-500 hover:bg-amber-600 text-white transition-all shadow-lg shadow-amber-500/20 hover:shadow-amber-500/40 flex items-center gap-2">
            <FileJson size={18} /> Generate Diagram
          </button>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { 
  Settings, MousePointer2, BoxSelect, Copy, AlignHorizontalSpaceAround, AlignVerticalSpaceAround, 
  Trash2, Key, Link as LinkIcon, Plus, X, ChevronLeft, ChevronRight, Palette, Triangle, Hash 
} from 'lucide-react';
import { DATA_TYPES } from '../../hooks/useDiagramState';

export function AttrToggle({ icon, label, active, onClick, title }) {
  return (
    <button onClick={onClick} title={title} className={`flex items-center gap-1.5 px-1.5 py-1 rounded text-[10px] font-bold uppercase transition-colors ${active ? 'bg-sky-100 text-sky-700 ring-1 ring-sky-300' : 'bg-neutral-100/50 text-neutral-500 hover:bg-neutral-200'}`}>
      {icon} {label}
    </button>
  );
}

export default function Sidebar({ 
  selectedItem, setSelectedItem, nodes, edges, 
  updateSelectedNode, updateEdgeProperties, deleteSelectedItem, 
  handleDuplicate, alignNeighbors, createAggregation, commitAction, clearCanvas,
  darkMode
}) {
  const activeNode = selectedItem?.type === 'node' ? nodes.find(n => n.id === selectedItem.id) : null;
  const activeEdge = selectedItem?.type === 'edge' ? edges.find(e => e.id === selectedItem.id) : null;

  return (
    <div className={`w-[360px] ${darkMode ? 'bg-neutral-900/80 border-neutral-700 text-neutral-200' : 'bg-white/80 border-white/40 text-neutral-800'} backdrop-blur-xl border-l flex flex-col shadow-[-10px_0_30px_rgba(0,0,0,0.03)] z-20 font-sans absolute right-0 top-0 bottom-0 pointer-events-auto`}>
      <div className={`h-14 ${darkMode ? 'border-neutral-800 bg-neutral-900/50' : 'border-neutral-200/50 bg-white/50'} border-b flex items-center px-4 gap-2 font-semibold shrink-0`}>
        <Settings size={18} className={darkMode ? 'text-neutral-400' : 'text-neutral-500'} /> Properties
      </div>

      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
        {!selectedItem && (
          <div className={`h-full flex flex-col items-center justify-center ${darkMode ? 'text-neutral-500' : 'text-neutral-400'} text-sm text-center px-4 gap-3`}>
            <MousePointer2 size={32} className="opacity-30" />
            <p>Select an element to edit properties.</p>
          </div>
        )}

        {activeNode && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
            
            <div className={`flex justify-between items-center ${darkMode ? 'bg-neutral-800/60 border-neutral-700' : 'bg-white/60 border-neutral-200/50'} p-1.5 rounded-lg border shadow-sm`}>
              {activeNode.shape === 'diamond' && (
                <button onClick={createAggregation} title="Wrap in Aggregation Box" className="p-2 text-sky-600 hover:text-sky-700 hover:bg-sky-500/10 rounded-md transition-colors">
                  <BoxSelect size={16} />
                </button>
              )}
              <button onClick={handleDuplicate} title="Duplicate Node" className={`p-2 ${darkMode ? 'text-neutral-400 hover:text-sky-400 hover:bg-neutral-800' : 'text-neutral-600 hover:text-sky-600 hover:bg-white'} rounded-md transition-colors`}>
                <Copy size={16} />
              </button>
              <div className={`w-px h-4 ${darkMode ? 'bg-neutral-700' : 'bg-neutral-300'}`}></div>
              <button onClick={() => alignNeighbors('y')} title="Align Connected Horizontally" className={`p-2 ${darkMode ? 'text-neutral-400 hover:text-sky-400 hover:bg-neutral-800' : 'text-neutral-600 hover:text-sky-600 hover:bg-white'} rounded-md transition-colors`}>
                <AlignHorizontalSpaceAround size={16} />
              </button>
              <button onClick={() => alignNeighbors('x')} title="Align Connected Vertically" className={`p-2 ${darkMode ? 'text-neutral-400 hover:text-sky-400 hover:bg-neutral-800' : 'text-neutral-600 hover:text-sky-600 hover:bg-white'} rounded-md transition-colors`}>
                <AlignVerticalSpaceAround size={16} />
              </button>
            </div>

            {activeNode.shape !== 'isa' && (
              <div className="space-y-2">
                <label className="text-[11px] font-bold text-neutral-500 uppercase tracking-wider">Name</label>
                <input 
                  type="text" value={activeNode.name} 
                  onChange={(e) => updateSelectedNode({ name: e.target.value.replace(/[^a-zA-Z0-9_]/g, '') })} 
                  onBlur={() => commitAction(nodes, edges)}
                  className={`w-full ${darkMode ? 'bg-neutral-800 border-neutral-700 text-neutral-100 focus:border-sky-500' : 'bg-white/60 border-neutral-300 focus:border-sky-500'} border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-sky-500/20 transition-all shadow-sm`} 
                />
              </div>
            )}

            {(activeNode.shape === 'rectangle' || activeNode.shape === 'diamond') && (
              <div className={`flex items-center gap-3 ${darkMode ? 'bg-neutral-800/60 border-neutral-700' : 'bg-white/60 border-neutral-200/50'} p-3 rounded-lg border shadow-sm`}>
                <input type="checkbox" checked={activeNode.isWeak} onChange={(e) => updateSelectedNode({ isWeak: e.target.checked }, true)} className="w-4 h-4 accent-sky-600 rounded cursor-pointer" id="weak-toggle" />
                <label htmlFor="weak-toggle" className={`text-sm font-medium ${darkMode ? 'text-neutral-300' : 'text-neutral-700'} cursor-pointer select-none flex-1`}>
                  {activeNode.shape === 'rectangle' ? 'Weak Entity (Double Border)' : 'Identifying Rel. (Double Border)'}
                </label>
              </div>
            )}

            {activeNode.shape === 'rectangle' && (
              <div className="space-y-2 pt-2">
                <label className="text-[11px] font-bold text-neutral-500 uppercase tracking-wider flex items-center gap-1"><Palette size={12}/> Header Color</label>
                <div className={`flex flex-wrap gap-2 p-2 ${darkMode ? 'bg-neutral-800/60 border-neutral-700' : 'bg-white/60 border-neutral-200/50'} rounded-lg border shadow-sm`}>
                  {[
                    'bg-[#bae6fd]', 'bg-[#fecaca]', 'bg-[#bbf7d0]', 'bg-[#fef08a]', 'bg-[#e9d5ff]', 
                    'bg-[#f1f5f9]', 'bg-[#fed7aa]', 'bg-[#fbcfe8]', 'bg-[#d9f99d]', 'bg-[#99f6e4]'
                  ].map(color => (
                    <button 
                      key={color} onClick={() => updateSelectedNode({ color }, true)} 
                      className={`w-6 h-6 rounded-full border-2 ${activeNode.color === color ? (darkMode ? 'border-sky-400 scale-110' : 'border-neutral-800') : 'border-transparent'} ${color} hover:scale-110 transition-transform shadow-sm`} 
                    />
                  ))}
                </div>
              </div>
            )}

            {activeNode.shape === 'rectangle' && (
              <div className="space-y-3 pt-2">
                <div className="flex items-center justify-between">
                  <label className="text-[11px] font-bold text-neutral-500 uppercase tracking-wider">Columns</label>
                  <button onClick={() => updateSelectedNode({ attributes: [...(activeNode.attributes || []), { id: `a_${Date.now()}`, name: 'new_col', type: 'VARCHAR(255)', isPK: false, isFK: false, isNullable: true, isPartialKey: false, indent: 0 }] }, true)} className={`p-1.5 ${darkMode ? 'hover:bg-neutral-800 bg-neutral-900/50 border-neutral-700' : 'hover:bg-white bg-white/50 border-neutral-200/50'} border shadow-sm rounded-md text-sky-500 transition-all`}><Plus size={14} /></button>
                </div>
                <div className="space-y-2">
                  {activeNode.attributes?.map(attr => (
                    <div key={attr.id} className={`${darkMode ? 'bg-neutral-800/80 border-neutral-700' : 'bg-white/80 border-neutral-200/80'} backdrop-blur-sm border p-2.5 rounded-lg shadow-sm space-y-2 group/attr transition-all hover:shadow-md`}>
                      <div className="flex items-center gap-1">
                         <button onClick={() => updateSelectedNode({ attributes: (activeNode.attributes || []).filter(a => a.id !== attr.id) }, true)} className="text-neutral-400 hover:text-red-500 p-1 bg-red-50/0 hover:bg-red-500/10 rounded" title="Delete Attribute"><X size={14} /></button>
                         <div className={`flex border ${darkMode ? 'border-neutral-700' : 'border-neutral-200'} rounded overflow-hidden mr-1`}>
                           <button onClick={() => updateSelectedNode({ attributes: (activeNode.attributes || []).map(a => a.id === attr.id ? {...a, indent: Math.max(0, (a.indent || 0) - 1)} : a) }, true)} disabled={(attr.indent || 0) <= 0} className={`${darkMode ? 'bg-neutral-800 hover:bg-neutral-700 disabled:opacity-20' : 'bg-neutral-100 hover:bg-neutral-200 disabled:opacity-30'} p-0.5 transition-colors`} title="Outdent"><ChevronLeft size={14}/></button>
                           <button onClick={() => updateSelectedNode({ attributes: (activeNode.attributes || []).map(a => a.id === attr.id ? {...a, indent: Math.min(2, (a.indent || 0) + 1)} : a) }, true)} disabled={(attr.indent || 0) >= 2} className={`${darkMode ? 'bg-neutral-800 hover:bg-neutral-700 disabled:opacity-20 border-neutral-700' : 'bg-neutral-100 hover:bg-neutral-200 disabled:opacity-30 border-neutral-200'} p-0.5 border-l transition-colors`} title="Indent (Make Child)"><ChevronRight size={14}/></button>
                         </div>
                         <input 
                            value={attr.name} onChange={(e) => updateSelectedNode({ attributes: (activeNode.attributes || []).map(a => a.id === attr.id ? { ...a, name: e.target.value.replace(/[^a-zA-Z0-9_]/g, '') } : a) })} 
                            onBlur={() => commitAction(nodes, edges)}
                            className={`w-24 min-w-0 border-none ${darkMode ? 'bg-neutral-900/50 text-neutral-100 focus:bg-neutral-900' : 'bg-neutral-100/50 focus:bg-white'} rounded px-1.5 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-sky-500/20 transition-all`} 
                          />
                         <select value={attr.type} onChange={(e) => updateSelectedNode({ attributes: (activeNode.attributes || []).map(a => a.id === attr.id ? { ...a, type: e.target.value } : a) }, true)} className={`flex-1 border ${darkMode ? 'border-neutral-700 bg-neutral-900 text-neutral-300' : 'border-neutral-200/80 bg-neutral-50/80'} rounded px-1 py-1 text-[11px] font-mono focus:outline-none focus:border-sky-500 transition-colors`}>
                           {DATA_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                         </select>
                      </div>
                      <div className="flex flex-wrap items-center gap-1.5 pl-7">
                         <AttrToggle icon={<Key size={12}/>} label="PK" active={attr.isPK} onClick={() => updateSelectedNode({ attributes: activeNode.attributes.map(a => a.id === attr.id ? { ...a, isPK: !a.isPK, isPartialKey: false } : a) }, true)} title="Primary Key" />
                         <AttrToggle icon={<Hash size={12}/>} label="Partial" active={attr.isPartialKey} onClick={() => updateSelectedNode({ attributes: activeNode.attributes.map(a => a.id === attr.id ? { ...a, isPartialKey: !a.isPartialKey, isPK: false } : a) }, true)} title="Partial Key (Weak Entity Discriminator)" />
                         <AttrToggle icon={<span className="font-mono text-[11px] leading-none">{'{}'}</span>} label="Multi" active={attr.isMultivalued} onClick={() => updateSelectedNode({ attributes: activeNode.attributes.map(a => a.id === attr.id ? { ...a, isMultivalued: !a.isMultivalued } : a) }, true)} title="Multivalued Attribute" />
                         <AttrToggle icon={<span className="font-mono text-[11px] leading-none">{'()'}</span>} label="Derived" active={attr.isDerived} onClick={() => updateSelectedNode({ attributes: activeNode.attributes.map(a => a.id === attr.id ? { ...a, isDerived: !a.isDerived } : a) }, true)} title="Derived Attribute" />
                         <AttrToggle icon={<span className="font-mono text-[11px] leading-none">{'Ø'}</span>} label="Null" active={attr.isNullable} onClick={() => updateSelectedNode({ attributes: activeNode.attributes.map(a => a.id === attr.id ? { ...a, isNullable: !a.isNullable } : a) }, true)} title="Allow Null Values" />
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeNode.shape === 'isa' && (
              <div className="space-y-3 pt-2">
                <label className="text-[11px] font-bold text-neutral-500 uppercase tracking-wider flex items-center gap-2">
                  <Triangle size={14}/> Specialization (ISA)
                </label>
                <div className={`${darkMode ? 'bg-neutral-800/50 border-sky-900/50 text-sky-400' : 'bg-white/80 border-sky-200/80 text-sky-800'} border p-3 rounded-lg shadow-sm space-y-3`}>
                  <div className="text-xs font-semibold mb-1">Select Superclass (Parent Entity):</div>
                  {edges.filter(e => e.source === activeNode.id || e.target === activeNode.id).map(edge => {
                    const connectedNode = nodes.find(n => n.id === (edge.source === activeNode.id ? edge.target : edge.source));
                    if (!connectedNode) return null;
                    return (
                      <label key={edge.id} className={`flex items-center gap-2 cursor-pointer p-1.5 ${darkMode ? 'hover:bg-sky-900/20 hover:border-sky-900/30' : 'hover:bg-sky-50 hover:border-sky-100'} rounded transition-colors border border-transparent`}>
                        <input type="radio" name={`isa-parent-${activeNode.id}`} checked={activeNode.parentId === connectedNode.id} onChange={() => updateSelectedNode({ parentId: connectedNode.id }, true)} className="accent-sky-600" />
                        <span className={`text-sm font-medium ${darkMode ? 'text-neutral-300' : 'text-neutral-700'}`}>{connectedNode.name}</span>
                      </label>
                    );
                  })}
                </div>
                <div className="flex items-center gap-2 pt-2">
                   <select value={activeNode.constraint || 'disjoint'} onChange={(e) => updateSelectedNode({ constraint: e.target.value }, true)} className={`flex-1 border ${darkMode ? 'border-neutral-700 bg-neutral-800 text-neutral-200' : 'border-neutral-200 bg-white'} rounded-md text-xs px-2 py-2 shadow-sm focus:border-sky-500 focus:outline-none`}>
                     <option value="disjoint">Disjoint (d)</option><option value="overlapping">Overlapping (o)</option>
                   </select>
                   <select value={activeNode.completeness || 'partial'} onChange={(e) => updateSelectedNode({ completeness: e.target.value }, true)} className={`flex-1 border ${darkMode ? 'border-neutral-700 bg-neutral-800 text-neutral-200' : 'border-neutral-200 bg-white'} rounded-md text-xs px-2 py-2 shadow-sm focus:border-sky-500 focus:outline-none`}>
                     <option value="partial">Partial</option><option value="total">Total</option>
                   </select>
                </div>
              </div>
            )}
          </div>
        )}

        {activeEdge && (
           <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="space-y-2">
                <label className="text-[11px] font-bold text-neutral-500 uppercase tracking-wider">Edge Label / Constraint</label>
                <input 
                  type="text" value={activeEdge.label || ''} 
                  onChange={(e) => updateEdgeProperties(activeEdge.id, { label: e.target.value })} 
                  onBlur={() => commitAction(nodes, edges)}
                  placeholder="e.g. 0..N, role_name"
                  className={`w-full ${darkMode ? 'bg-neutral-800 border-neutral-700 text-neutral-100 focus:border-sky-500' : 'bg-white/60 border-neutral-300 focus:border-sky-500'} border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-sky-500/20 transition-all shadow-sm`} 
                />
              </div>
              <div className={`flex items-center gap-3 ${darkMode ? 'bg-neutral-800/80 border-neutral-700' : 'bg-white/80 border-neutral-200/80'} p-3 rounded-lg border shadow-sm`}>
                <input type="checkbox" checked={activeEdge.dashed} onChange={(e) => updateEdgeProperties(activeEdge.id, { dashed: e.target.checked }, true)} className="w-4 h-4 accent-sky-600 rounded cursor-pointer" id="dash-toggle" />
                <label htmlFor="dash-toggle" className={`text-sm font-medium ${darkMode ? 'text-neutral-300' : 'text-neutral-700'} cursor-pointer select-none flex-1`}>
                  Dashed Line (for attributes)
                </label>
              </div>
           </div>
        )}
      </div>

      <div className={`p-4 ${darkMode ? 'border-neutral-800 bg-neutral-900/50' : 'border-neutral-200/50 bg-white/50'} border-t space-y-2 shrink-0`}>
         <button onClick={deleteSelectedItem} disabled={!selectedItem} className={`w-full py-2.5 ${darkMode ? 'bg-red-900/20 hover:bg-red-900/30 text-red-400 border-red-900/30' : 'bg-red-50 hover:bg-red-100 text-red-600 border-red-100'} border disabled:opacity-40 rounded-lg flex items-center justify-center gap-2 font-medium transition-all text-sm shadow-sm hover:shadow-md`}><Trash2 size={16} /> Delete Selected</button>
         <button onClick={clearCanvas} className={`w-full py-2.5 ${darkMode ? 'bg-neutral-800 hover:bg-neutral-700 text-neutral-300 border-neutral-700' : 'bg-white hover:bg-neutral-50 text-neutral-700 border-neutral-200'} border rounded-lg flex items-center justify-center font-medium transition-all text-sm shadow-sm hover:shadow-md`}>Clear Canvas</button>
      </div>
    </div>
  );
}
